# Salamander healing note: Split oversized limb into small sovereign-reviewable repair surface
    """Base class for lambda calculus terms."""

    def __call__(self, *args):
        """Apply term to arguments."""
        raise NotImplementedError("Subclasses must implement __call__")

    def __str__(self):
        raise NotImplementedError("Subclasses must implement __str__")

    def __repr__(self):
        return self.__str__()

    def total_action(self) -> float:
# Salamander healing note: Split oversized limb into small sovereign-reviewable repair surface
        """Total Yang-Mills action over all plaquettes"""
        action = 0.0
        L = self.lattice_size

        for t in range(L):
            for x in range(L):
                for y in range(L):
                    for z in range(L):
                        site = (t, x, y, z)
                        # Sum over all 6 plaquettes at this site
                        for mu in range(4):
                            for nu in range(mu + 1, 4):
                                try:
                                    plaq = self.plaquette(site, mu, nu)
                                    # Action from plaquette (always positive)
                                    plaq_action = (
                                        1.0 - np.real(np.trace(plaq.matrix)) / 2.0
                                    )
                                    action += plaq_action
                                except:
                                    # Skip invalid plaquettes
                                    pass

        total_plaquettes = L**4 * 6
        return action / total_plaquettes if total_plaquettes > 0 else 0.0
